import requests
import json

def send_message(channel: str, text: str, thread_ts: str = "") -> str:
    """Send a message to a Slack channel or user. The channel can be a channel ID (e.g. C01ABC123), a channel name (e.g. general or #general), or a user ID for DMs. If thread_ts is provided, the message is sent as a threaded reply."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured. Please set it in Environment Variables."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}", "Content-Type": "application/json"}
    # If channel looks like a name (no leading C/D/G or not alphanumeric pattern), try to resolve it
    clean_channel = channel.lstrip('#')
    payload = {"channel": clean_channel, "text": text}
    if thread_ts:
        payload["thread_ts"] = thread_ts
    try:
        resp = requests.post("https://slack.com/api/chat.postMessage", headers=headers, json=payload, timeout=30)
        data = resp.json()
        if data.get("ok"):
            ts = data.get("ts", "")
            ch = data.get("channel", clean_channel)
            return f"Message sent successfully to {ch} (timestamp: {ts})"
        else:
            return f"Error sending message: {data.get('error', 'Unknown error')}. Hint: Make sure the bot is invited to the channel and the channel ID/name is correct."
    except Exception as e:
        return f"Exception sending message: {str(e)}"


def search_messages(query: str, count: int = 20) -> str:
    """Search for messages across the Slack workspace. Requires a user token with search:read scope. The query supports Slack search modifiers like 'in:#channel', 'from:@user', 'before:2024-01-01', etc."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}"}
    params = {"query": query, "count": min(count, 100), "sort": "timestamp", "sort_dir": "desc"}
    try:
        resp = requests.get("https://slack.com/api/search.messages", headers=headers, params=params, timeout=30)
        data = resp.json()
        if data.get("ok"):
            matches = data.get("messages", {}).get("matches", [])
            if not matches:
                return "No messages found matching the query."
            results = []
            for m in matches:
                user = m.get("username", m.get("user", "unknown"))
                text = m.get("text", "")[:200]
                channel_name = m.get("channel", {}).get("name", "unknown") if isinstance(m.get("channel"), dict) else "unknown"
                ts = m.get("ts", "")
                results.append(f"- [{channel_name}] {user}: {text} (ts: {ts})")
            total = data.get("messages", {}).get("total", len(matches))
            return f"Found {total} messages (showing {len(matches)}):\n" + "\n".join(results)
        else:
            return f"Error searching: {data.get('error', 'Unknown error')}. Note: search.messages requires a user token (xoxp-), not a bot token."
    except Exception as e:
        return f"Exception searching messages: {str(e)}"


def get_channel_history(channel: str, limit: int = 20) -> str:
    """Retrieve recent messages from a Slack channel. Channel should be a channel ID (e.g. C01ABC123). Limit controls how many messages to fetch (max 100)."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}"}
    params = {"channel": channel, "limit": min(limit, 100)}
    try:
        resp = requests.get("https://slack.com/api/conversations.history", headers=headers, params=params, timeout=30)
        data = resp.json()
        if data.get("ok"):
            messages = data.get("messages", [])
            if not messages:
                return "No messages found in this channel."
            results = []
            for m in messages:
                user = m.get("user", "bot/app")
                text = m.get("text", "")[:300]
                ts = m.get("ts", "")
                results.append(f"- [{ts}] {user}: {text}")
            return f"Last {len(messages)} messages:\n" + "\n".join(results)
        else:
            return f"Error fetching history: {data.get('error', 'Unknown error')}"
    except Exception as e:
        return f"Exception: {str(e)}"


