def list_channels(limit: int = 100, include_private: bool = False) -> str:
    """List all channels in the workspace. Set include_private=True to also include private channels the bot is a member of. Returns channel names and IDs."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}"}
    types = "public_channel,private_channel" if include_private else "public_channel"
    params = {"limit": min(limit, 1000), "types": types, "exclude_archived": True}
    try:
        all_channels = []
        cursor = None
        while True:
            if cursor:
                params["cursor"] = cursor
            resp = requests.get("https://slack.com/api/conversations.list", headers=headers, params=params, timeout=30)
            data = resp.json()
            if not data.get("ok"):
                return f"Error listing channels: {data.get('error', 'Unknown error')}"
            all_channels.extend(data.get("channels", []))
            cursor = data.get("response_metadata", {}).get("next_cursor", "")
            if not cursor or len(all_channels) >= limit:
                break
        if not all_channels:
            return "No channels found."
        results = []
        for ch in all_channels[:limit]:
            name = ch.get("name", "unknown")
            ch_id = ch.get("id", "")
            is_private = ch.get("is_private", False)
            members = ch.get("num_members", "?")
            purpose = ch.get("purpose", {}).get("value", "")[:80]
            ptype = "🔒" if is_private else "#"
            results.append(f"{ptype} {name} (ID: {ch_id}) — {members} members — {purpose}")
        return f"Found {len(all_channels)} channels:\n" + "\n".join(results)
    except Exception as e:
        return f"Exception: {str(e)}"


