import requests
import json

def list_users(limit: int = 100) -> str:
    """List all users in the Slack workspace. Returns user names, display names, and IDs."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}"}
    params = {"limit": min(limit, 1000)}
    try:
        all_users = []
        cursor = None
        while True:
            if cursor:
                params["cursor"] = cursor
            resp = requests.get("https://slack.com/api/users.list", headers=headers, params=params, timeout=30)
            data = resp.json()
            if not data.get("ok"):
                return f"Error listing users: {data.get('error', 'Unknown error')}"
            all_users.extend(data.get("members", []))
            cursor = data.get("response_metadata", {}).get("next_cursor", "")
            if not cursor or len(all_users) >= limit:
                break
        if not all_users:
            return "No users found."
        results = []
        for u in all_users[:limit]:
            if u.get("deleted") or u.get("is_bot"):
                continue
            name = u.get("real_name", u.get("name", "unknown"))
            display = u.get("profile", {}).get("display_name", "")
            uid = u.get("id", "")
            email = u.get("profile", {}).get("email", "N/A")
            status = u.get("profile", {}).get("status_text", "")
            is_admin = "(admin)" if u.get("is_admin") else ""
            display_str = f" ({display})" if display else ""
            results.append(f"- {name}{display_str} — ID: {uid} — {email} {is_admin}")
        return f"Found {len(results)} users:\n" + "\n".join(results)
    except Exception as e:
        return f"Exception: {str(e)}"


