def upload_text_snippet(channels: str, content: str, title: str = "Snippet", filetype: str = "text") -> str:
    """Upload a text snippet/file to one or more Slack channels. Provide comma-separated channel IDs in 'channels', the text content, an optional title, and filetype (e.g. 'python', 'javascript', 'json', 'text', 'markdown')."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}"}
    payload = {
        "content": content,
        "title": title,
        "filetype": filetype,
        "channels": channels
    }
    try:
        resp = requests.post("https://slack.com/api/files.upload", headers=headers, data=payload, timeout=60)
        data = resp.json()
        if data.get("ok"):
            f = data.get("file", {})
            return f"File uploaded successfully!\nTitle: {f.get('title')}\nID: {f.get('id')}\nURL: {f.get('permalink', 'N/A')}"
        else:
            return f"Error uploading file: {data.get('error', 'Unknown error')}"
    except Exception as e:
        return f"Exception: {str(e)}"


def list_files(channel: str = "", count: int = 20) -> str:
    """List recent files in the workspace or a specific channel. Optionally provide a channel ID to filter."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}"}
    params = {"count": min(count, 100)}
    if channel:
        params["channel"] = channel
    try:
        resp = requests.get("https://slack.com/api/files.list", headers=headers, params=params, timeout=30)
        data = resp.json()
        if data.get("ok"):
            files = data.get("files", [])
            if not files:
                return "No files found."
            results = []
            for f in files:
                title = f.get("title", f.get("name", "Untitled"))
                ftype = f.get("filetype", "unknown")
                fid = f.get("id", "")
                size = f.get("size", 0)
                url = f.get("permalink", "N/A")
                results.append(f"- {title} ({ftype}, {size} bytes) — ID: {fid} — {url}")
            return f"Found {len(files)} files:\n" + "\n".join(results)
        else:
            return f"Error: {data.get('error', 'Unknown error')}"
    except Exception as e:
        return f"Exception: {str(e)}"


def delete_file(file_id: str) -> str:
    """Delete a file from Slack. Provide the file ID."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}", "Content-Type": "application/json"}
    payload = {"file": file_id}
    try:
        resp = requests.post("https://slack.com/api/files.delete", headers=headers, json=payload, timeout=30)
        data = resp.json()
        if data.get("ok"):
            return f"File {file_id} deleted successfully."
        else:
            return f"Error: {data.get('error', 'Unknown error')}"
    except Exception as e:
        return f"Exception: {str(e)}"


