def list_pins(channel: str) -> str:
    """List all pinned items in a channel. Provide the channel ID."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}"}
    params = {"channel": channel}
    try:
        resp = requests.get("https://slack.com/api/pins.list", headers=headers, params=params, timeout=30)
        data = resp.json()
        if data.get("ok"):
            items = data.get("items", [])
            if not items:
                return "No pinned items in this channel."
            results = []
            for item in items:
                msg = item.get("message", {})
                text = msg.get("text", "")[:150]
                user = msg.get("user", "unknown")
                ts = msg.get("ts", "")
                results.append(f"- [{ts}] {user}: {text}")
            return f"{len(items)} pinned items:\n" + "\n".join(results)
        else:
            return f"Error: {data.get('error', 'Unknown error')}"
    except Exception as e:
        return f"Exception: {str(e)}"


def add_reminder(text: str, time: str, user: str = "") -> str:
    """Set a reminder in Slack. 'text' is the reminder text, 'time' is when (e.g. 'in 5 minutes', 'tomorrow at 9am', '2024-12-25 10:00', Unix timestamp). Optionally set 'user' to remind a specific user by ID."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}", "Content-Type": "application/json"}
    payload = {"text": text, "time": time}
    if user:
        payload["user"] = user
    try:
        resp = requests.post("https://slack.com/api/reminders.add", headers=headers, json=payload, timeout=30)
        data = resp.json()
        if data.get("ok"):
            r = data.get("reminder", {})
            return f"Reminder set!\nText: {r.get('text', text)}\nTime: {r.get('time', time)}\nID: {r.get('id', 'N/A')}"
        else:
            return f"Error: {data.get('error', 'Unknown error')}"
    except Exception as e:
        return f"Exception: {str(e)}"


def open_dm(user_id: str) -> str:
    """Open a direct message conversation with a user. Returns the DM channel ID which can be used to send messages. Provide the user ID."""
    if not SLACK_BOT_TOKEN:
        return "Error: SLACK_BOT_TOKEN is not configured."
    headers = {"Authorization": f"Bearer {SLACK_BOT_TOKEN}", "Content-Type": "application/json"}
    payload = {"users": user_id}
    try:
        resp = requests.post("https://slack.com/api/conversations.open", headers=headers, json=payload, timeout=30)
        data = resp.json()
        if data.get("ok"):
            ch = data.get("channel", {})
            return f"DM channel opened. Channel ID: {ch.get('id', 'N/A')} — Use this ID to send messages to the user."
        else:
            return f"Error: {data.get('error', 'Unknown error')}"
    except Exception as e:
        return f"Exception: {str(e)}"
